// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import {
  getOverview,
  getRides,
  getApprovedCaptains,
  getPendingCaptains,
} from "../../services/adminApi";
import { Paper, Typography, Table, TableHead, TableBody, TableRow, TableCell } from "@mui/material";

export default function AdminDashboard() {
  const [overview, setOverview] = useState({});
  const [rides, setRides] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(true);
    Promise.all([getOverview(), getRides(), getApprovedCaptains(), getPendingCaptains()])
      .then(([overviewRes, ridesRes, approvedRes, pendingRes]) => {
        setOverview({
          users: overviewRes.data.users,
          riders: overviewRes.data.riders,
          captains: approvedRes.data.captains.length,
          pendingCaptains: pendingRes.data.pendingCaptains.length,
          rides: overviewRes.data.rides,
        });
        setRides(ridesRes.data.rides);
      })
      .catch(err => console.error("Admin Dashboard API error:", err))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <Typography>Loading...</Typography>;

  return (
    <div>
      <Typography variant="h4" gutterBottom>
        Admin Dashboard
      </Typography>

      <Paper sx={{ p: 2, mb: 3 }}>
        <Typography>Users: {overview.users}</Typography>
        <Typography>Riders: {overview.riders}</Typography>
        <Typography>Approved Captains: {overview.captains}</Typography>
        <Typography>Pending Captains: {overview.pendingCaptains}</Typography>
        <Typography>Total Rides: {overview.rides}</Typography>
      </Paper>

      <Paper sx={{ p: 2 }}>
        <Typography variant="h6" gutterBottom>
          Recent Rides
        </Typography>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>Rider</TableCell>
              <TableCell>Captain</TableCell>
              <TableCell>Pickup</TableCell>
              <TableCell>Drop</TableCell>
              <TableCell>Fare</TableCell>
              <TableCell>Status</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {rides.length === 0 ? (
              <TableRow>
                <TableCell colSpan={6} align="center">
                  No rides found
                </TableCell>
              </TableRow>
            ) : (
              rides.map(ride => (
                <TableRow key={ride._id}>
                  <TableCell>{ride.riderId?.fullName || "-"}</TableCell>
                  <TableCell>{ride.captainId?.fullName || "-"}</TableCell>
                  <TableCell>{ride.pickup}</TableCell>
                  <TableCell>{ride.drop}</TableCell>
                  <TableCell>{ride.fare}</TableCell>
                  <TableCell>{ride.status}</TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </Paper>
    </div>
  );
}
